 42→async function parseJsonBody<T>(request: Request): Promise<T | Response> {
 43→  try {
 44→    return (await request.json()) as T;
 45→  } catch {
 46→    return jsonError("invalid JSON body", 400);
 47→  }
 48→}
 49→
 50→async function resolveWorkspace(
 51→  deps: ServerDependencies,
 52→  workspaceId: string,
 53→  logEvent: string,
 54→): Promise<RecordId<"workspace", string> | Response> {
 55→  try {
 56→    return await resolveWorkspaceRecord(deps.surreal, workspaceId);
 57→  } catch (error) {
 58→    if (error instanceof HttpError) {
 59→      return jsonError(error.message, error.status);
 60→    }
 61→    logError(logEvent, "Failed to resolve workspace", error, { workspaceId });
 62→    return jsonError("failed to resolve workspace", 500);
 63→  }
 64→}
 65→
 66→function isResponse(value: unknown): value is Response {
 67→  return value instanceof Response;
 68→}
