191→// ---------------------------------------------------------------------------
192→// GET /api/workspaces/:workspaceId/learnings
193→// ---------------------------------------------------------------------------
194→
195→async function handleListLearnings(
196→  deps: ServerDependencies,
197→  workspaceId: string,
198→  request: Request,
199→): Promise<Response> {
200→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.list.workspace_resolve.failed");
201→  if (isResponse(workspaceOrError)) return workspaceOrError;
202→  const workspaceRecord = workspaceOrError;
203→
204→  try {
205→    const url = new URL(request.url);
206→    const statusParam = url.searchParams.get("status") ?? undefined;
207→    const typeParam = url.searchParams.get("type") ?? undefined;
208→    const agentParam = url.searchParams.get("agent") ?? undefined;
209→
210→    const learnings = await listWorkspaceLearnings({
211→      surreal: deps.surreal,
212→      workspaceRecord,
213→      status: statusParam as LearningStatus | undefined,
214→      learningType: typeParam as LearningType | undefined,
215→      agentType: agentParam,
216→    });
217→
218→    // Return snake_case fields to match HTTP contract
219→    const items = learnings.map((l) => ({
220→      id: l.id,
221→      text: l.text,
222→      learning_type: l.learningType,
223→      status: l.status,
224→      source: l.source,
225→      priority: l.priority,
226→      target_agents: l.targetAgents,
227→      ...(l.suggestedBy ? { suggested_by: l.suggestedBy } : {}),
228→      ...(l.patternConfidence !== undefined ? { pattern_confidence: l.patternConfidence } : {}),
229→      created_at: l.createdAt,
230→      ...(l.approvedAt ? { approved_at: l.approvedAt } : {}),
231→      ...(l.dismissedAt ? { dismissed_at: l.dismissedAt } : {}),
232→      ...(l.dismissedReason ? { dismissed_reason: l.dismissedReason } : {}),
233→      ...(l.deactivatedAt ? { deactivated_at: l.deactivatedAt } : {}),
234→    }));
235→
236→    return jsonResponse({ learnings: items }, 200);
237→  } catch (error) {
238→    logError("learning.list.failed", "Failed to list learnings", error, { workspaceId });
239→    return jsonError("failed to list learnings", 500);
240→  }
241→}
242→
243→// ---------------------------------------------------------------------------
244→// POST /api/workspaces/:workspaceId/learnings/:learningId/actions
245→// ---------------------------------------------------------------------------
246→
247→type ActionBody = {
248→  action?: string;
249→  reason?: string;
250→  new_text?: string;
251→};
252→
253→async function handleLearningAction(
254→  deps: ServerDependencies,
255→  workspaceId: string,
256→  learningId: string,
257→  request: Request,
258→): Promise<Response> {
259→  const bodyOrError = await parseJsonBody<ActionBody>(request);
260→  if (isResponse(bodyOrError)) return bodyOrError;
261→  const body = bodyOrError;
262→
263→  if (!body.action || !(VALID_ACTIONS as readonly string[]).includes(body.action)) {
264→    return jsonError(
265→      `action must be one of: ${VALID_ACTIONS.join(", ")}`,
266→      400,
267→    );
268→  }
269→
270→  const action = body.action as LearningAction;
271→
272→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.action.workspace_resolve.failed");
273→  if (isResponse(workspaceOrError)) return workspaceOrError;
274→  const workspaceRecord = workspaceOrError;
275→
276→  // Look up the learning
277→  const learningRecord = new RecordId("learning", learningId) as LearningRecord;
278→  let existing: { status: LearningStatus; workspace: RecordId<"workspace", string> } | undefined;
279→  try {
280→    existing = await deps.surreal.select<{
281→      status: LearningStatus;
282→      workspace: RecordId<"workspace", string>;
283→    }>(learningRecord);
284→  } catch {
285→    // select returns undefined if not found
286→  }
287→
288→  if (!existing) {
289→    return jsonError("learning not found", 404);
290→  }
291→
292→  // Verify workspace scope
293→  if ((existing.workspace.id as string) !== (workspaceRecord.id as string)) {
294→    return jsonError("learning not found", 404);
295→  }
296→
297→  // Validate state transition
298→  const transitions = VALID_TRANSITIONS[existing.status];
299→  if (!transitions || !(action in transitions)) {
300→    return jsonError(
301→      `cannot ${action} a learning in status '${existing.status}'`,
302→      409,
303→    );
304→  }
305→
306→  const newStatus = transitions[action];
307→  const now = new Date();
308→
309→  try {
310→    // If approving with new_text, update text first
311→    if (action === "approve" && body.new_text) {
312→      await updateLearningText({
313→        surreal: deps.surreal,
314→        learningRecord,
315→        newText: body.new_text,
316→        now,
317→      });
318→    }
319→
320→    await updateLearningStatus({
321→      surreal: deps.surreal,
322→      workspaceRecord,
323→      learningRecord,
324→      newStatus,
325→      now,
326→      reason: body.reason,
327→    });
328→
329→    logInfo("learning.action.completed", "Learning action completed", {
330→      workspaceId,
331→      learningId,
332→      action,
333→      previousStatus: existing.status,
334→      newStatus,
335→    });
336→
337→    return jsonResponse({ status: newStatus }, 200);
338→  } catch (error) {
339→    logError("learning.action.failed", "Failed to perform learning action", error, {
340→      workspaceId,
341→      learningId,
342→      action,
343→    });
344→    return jsonError("failed to perform action", 500);
345→  }
346→}
347→
348→// ---------------------------------------------------------------------------
349→// PUT /api/workspaces/:workspaceId/learnings/:learningId
350→// ---------------------------------------------------------------------------
351→
352→type EditBody = {
353→  text?: string;
354→  priority?: string;
355→  target_agents?: string[];
356→};
357→
358→async function handleEditLearning(
359→  deps: ServerDependencies,
360→  workspaceId: string,
361→  learningId: string,
362→  request: Request,
363→): Promise<Response> {
364→  const bodyOrError = await parseJsonBody<EditBody>(request);
365→  if (isResponse(bodyOrError)) return bodyOrError;
366→  const body = bodyOrError;
367→
368→  // Validate text if provided: must not be empty or whitespace-only
369→  if (body.text !== undefined) {
370→    if (typeof body.text !== "string" || body.text.trim().length === 0) {
371→      return jsonError("text must not be empty", 400);
372→    }
373→  }
374→
375→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "learning.edit.workspace_resolve.failed");
376→  if (isResponse(workspaceOrError)) return workspaceOrError;
377→  const workspaceRecord = workspaceOrError;
378→
379→  const learningRecord = new RecordId("learning", learningId) as LearningRecord;
380→  const now = new Date();
381→
382→  // Re-embed if text changed
383→  let embedding: number[] | undefined;
384→  if (body.text !== undefined) {
385→    try {
386→      embedding = await createEmbeddingVector(
387→        deps.embeddingModel,
388→        body.text.trim(),
389→        deps.config.embeddingDimension,
390→      );
391→    } catch (error) {
392→      logWarn("learning.edit.embedding_failed", "Embedding regeneration failed, updating without", {
393→        workspaceId,
394→        learningId,
395→        error: error instanceof Error ? error.message : String(error),
396→      });
397→    }
398→  }
399→
400→  try {
401→    await updateLearningFields({
402→      surreal: deps.surreal,
403→      workspaceRecord,
404→      learningRecord,
405→      fields: {
406→        ...(body.text !== undefined ? { text: body.text.trim() } : {}),
407→        ...(body.priority !== undefined ? { priority: body.priority as "low" | "medium" | "high" } : {}),
408→        ...(body.target_agents !== undefined ? { targetAgents: body.target_agents } : {}),
409→      },
410→      now,
411→      embedding,
412→    });
413→
414→    logInfo("learning.edited", "Learning edited via HTTP", {
415→      workspaceId,
416→      learningId,
417→      fieldsChanged: Object.keys(body).filter((k) => (body as Record<string, unknown>)[k] !== undefined),
418→      reEmbedded: embedding !== undefined,
419→    });
420→
421→    return jsonResponse({ status: "updated" }, 200);
422→  } catch (error) {
423→    if (error instanceof LearningNotFoundError) {
424→      return jsonError("learning not found", 404);
425→    }
426→    if (error instanceof LearningNotActiveError) {
427→      return jsonError(error.message, 409);
428→    }
429→    logError("learning.edit.failed", "Failed to edit learning", error, {
430→      workspaceId,
431→      learningId,
432→    });
433→    return jsonError("failed to edit learning", 500);
434→  }
435→}
