  1→/**
  2→ * JIT learning loader for agent prompt injection.
  3→ *
  4→ * IO boundary: queries SurrealDB for active learnings.
  5→ * Pure budget logic is exported for unit testing.
  6→ */
  7→import { RecordId, type Surreal } from "surrealdb";
  8→import type { EntityPriority, LearningSource, LearningType } from "../../shared/contracts";
  9→import { logWarn } from "../http/observability";
 10→import { estimateTokens } from "./formatter";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Types
 14→// ---------------------------------------------------------------------------
 15→
 16→export type LoadedLearning = {
 17→  id: string;
 18→  text: string;
 19→  learningType: LearningType;
 20→  source: LearningSource;
 21→  priority: EntityPriority;
 22→  createdAt: string;
 23→  similarity?: number;
 24→};
 25→
 26→type LearningRow = {
 27→  id: RecordId<"learning", string>;
 28→  text: string;
 29→  learning_type: LearningType;
 30→  source: LearningSource;
 31→  priority: EntityPriority;
 32→  target_agents: string[];
 33→  created_at: string | Date;
 34→  similarity?: number;
 35→};
 36→
 37→export type TokenBudgetResult = {
 38→  learnings: LoadedLearning[];
 39→  constraintBudgetExceeded: boolean;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Priority sort (pure)
 44→// ---------------------------------------------------------------------------
 45→
 46→const SOURCE_RANK: Record<string, number> = { human: 0, agent: 1 };
 47→const PRIORITY_RANK: Record<string, number> = { high: 0, medium: 1, low: 2 };
 48→
 49→function compareLearningPriority(a: LoadedLearning, b: LoadedLearning): number {
 50→  const sourceCompare = (SOURCE_RANK[a.source] ?? 2) - (SOURCE_RANK[b.source] ?? 2);
 51→  if (sourceCompare !== 0) return sourceCompare;
 52→
 53→  const priorityCompare = (PRIORITY_RANK[a.priority] ?? 3) - (PRIORITY_RANK[b.priority] ?? 3);
 54→  if (priorityCompare !== 0) return priorityCompare;
 55→
 56→  // Newest first
 57→  return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
 58→}
 59→
 60→// ---------------------------------------------------------------------------
 61→// Token budget (pure)
 62→// ---------------------------------------------------------------------------
 63→
 64→const DEFAULT_TOKEN_BUDGET = 500;
 65→
 66→/**
 67→ * Applies token budget to sorted learnings.
 68→ *
 69→ * Rules:
 70→ * - Constraints are ALWAYS included, never dropped (even if they alone exceed budget)
 71→ * - Instructions fill remaining budget in priority order; oversized ones skipped
 72→ * - Precedents fill remaining budget by similarity order
 73→ */
 74→export function applyTokenBudget(
 75→  learnings: ReadonlyArray<LoadedLearning>,
 76→  tokenBudget: number = DEFAULT_TOKEN_BUDGET,
 77→): TokenBudgetResult {
 78→  const constraints = learnings.filter((l) => l.learningType === "constraint");
 79→  const instructions = learnings.filter((l) => l.learningType === "instruction");
 80→  const precedents = learnings.filter((l) => l.learningType === "precedent");
 81→
 82→  // Constraints always included
 83→  let usedTokens = constraints.reduce((sum, c) => sum + estimateTokens(c.text), 0);
 84→  const constraintBudgetExceeded = usedTokens > tokenBudget;
 85→  if (constraintBudgetExceeded) {
 86→    logWarn("learning.budget.constraints_exceeded", "Constraints alone exceed token budget", {
 87→      constraintTokens: usedTokens,
 88→      tokenBudget,
 89→      constraintCount: constraints.length,
 90→    });
 91→  }
 92→
 93→  // Instructions fill remaining budget; skip oversized, try next
 94→  const includedInstructions: LoadedLearning[] = [];
 95→  for (const instruction of instructions) {
 96→    const tokens = estimateTokens(instruction.text);
 97→    if (usedTokens + tokens <= tokenBudget) {
 98→      includedInstructions.push(instruction);
 99→      usedTokens += tokens;
100→    }
101→    // Skip oversized and try next (no break)
102→  }
103→
104→  // Precedents fill remaining budget by similarity (already sorted by similarity from query)
105→  const includedPrecedents: LoadedLearning[] = [];
106→  for (const precedent of precedents) {
107→    const tokens = estimateTokens(precedent.text);
108→    if (usedTokens + tokens <= tokenBudget) {
109→      includedPrecedents.push(precedent);
110→      usedTokens += tokens;
111→    }
112→  }
113→
114→  return {
115→    learnings: [...constraints, ...includedInstructions, ...includedPrecedents],
116→    constraintBudgetExceeded,
117→  };
118→}
119→
120→// ---------------------------------------------------------------------------
121→// Row mapping (pure)
122→// ---------------------------------------------------------------------------
123→
124→function toLoadedLearning(row: LearningRow): LoadedLearning {
125→  return {
126→    id: row.id.id as string,
127→    text: row.text,
128→    learningType: row.learning_type,
129→    source: row.source,
130→    priority: row.priority,
131→    createdAt: row.created_at instanceof Date
132→      ? row.created_at.toISOString()
133→      : new Date(row.created_at).toISOString(),
134→    ...(row.similarity !== undefined ? { similarity: row.similarity } : {}),
135→  };
136→}
137→
138→// ---------------------------------------------------------------------------
139→// Loader (IO boundary)
140→// ---------------------------------------------------------------------------
141→
142→/**
143→ * Loads active learnings for prompt injection, applying priority sort and token budget.
144→ *
145→ * 1. Queries constraints + instructions (non-semantic, priority-sorted)
146→ * 2. If contextEmbedding provided, queries precedents (semantic, similarity-sorted)
147→ * 3. Applies token budget (~500 tokens)
148→ */
149→export async function loadActiveLearnings(input: {
150→  surreal: Surreal;
151→  workspaceId: string;
152→  agentType: string;
153→  contextEmbedding?: number[];
154→  tokenBudget?: number;
155→}): Promise<TokenBudgetResult> {
156→  const workspaceRecord = new RecordId("workspace", input.workspaceId);
157→  const budget = input.tokenBudget ?? DEFAULT_TOKEN_BUDGET;
158→
159→  // Query constraints + instructions
160→  const [nonSemanticRows] = await input.surreal
161→    .query<[LearningRow[]]>(
162→      [
163→        "SELECT id, text, learning_type, source, priority, target_agents, created_at",
164→        "FROM learning",
165→        "WHERE workspace = $workspace",
166→        'AND status = "active"',
167→        'AND learning_type IN ["constraint", "instruction"]',
168→        "AND (array::len(target_agents) = 0 OR $agentType IN target_agents)",
169→        "ORDER BY created_at DESC",
170→        "LIMIT 50;",
171→      ].join(" "),
172→      { workspace: workspaceRecord, agentType: input.agentType },
173→    )
174→    .collect<[LearningRow[]]>();
175→
176→  const nonSemanticLearnings = nonSemanticRows.map(toLoadedLearning);
177→
178→  // Query precedents only when contextEmbedding is provided
179→  let precedentLearnings: LoadedLearning[] = [];
180→  if (input.contextEmbedding) {
181→    // Two-step KNN pattern (SurrealDB HNSW+WHERE bug workaround)
182→    const [candidates] = await input.surreal
183→      .query<[LearningRow[]]>(
184→        [
185→          "LET $candidates = SELECT id, text, learning_type, source, priority, target_agents, created_at, workspace,",
186→          "vector::similarity::cosine(embedding, $contextEmbedding) AS similarity",
187→          "FROM learning",
188→          "WHERE embedding <|20, COSINE|> $contextEmbedding;",
189→          "",
190→          "SELECT * FROM $candidates",
191→          "WHERE workspace = $workspace",
192→          'AND status = "active"',
193→          'AND learning_type = "precedent"',
194→          "AND (array::len(target_agents) = 0 OR $agentType IN target_agents)",
195→          "AND similarity > 0.70",
196→          "ORDER BY similarity DESC",
197→          "LIMIT 10;",
198→        ].join(" "),
199→        {
200→          workspace: workspaceRecord,
201→          agentType: input.agentType,
202→          contextEmbedding: input.contextEmbedding,
203→        },
204→      )
205→      .collect<[LearningRow[]]>();
206→
207→    precedentLearnings = candidates.map(toLoadedLearning);
208→  }
209→
210→  // Sort non-semantic by priority, then apply budget
211→  const sortedNonSemantic = [...nonSemanticLearnings].sort(compareLearningPriority);
212→  const allLearnings = [...sortedNonSemantic, ...precedentLearnings];
213→
214→  return applyTokenBudget(allLearnings, budget);
215→}
