454→// ---------------------------------------------------------------------------
455→// Dual gate: decide whether to propose learning or create observation
456→// ---------------------------------------------------------------------------
457→
458→/**
459→ * Applies the dual gate: should_propose_learning AND confidence >= threshold.
460→ */
461→function shouldProposeLearning(classification: RootCauseClassification): boolean {
462→  return classification.should_propose_learning && classification.confidence >= CONFIDENCE_THRESHOLD;
463→}
464→
465→/**
466→ * Maps a root cause classification to a CreateLearningInput.
467→ */
468→function rootCauseToLearningInput(
469→  classification: RootCauseClassification,
470→  cluster: ObservationCluster,
471→): CreateLearningInput {
472→  return {
473→    text: classification.proposed_learning_text,
474→    learningType: classification.proposed_learning_type,
475→    source: "agent",
476→    suggestedBy: "observer",
477→    patternConfidence: classification.confidence,
478→    targetAgents: classification.target_agents,
479→    evidenceIds: cluster.observations.map((obs) => ({
480→      table: "observation" as const,
481→      id: obs.id,
482→    })),
483→  };
484→}
