504→// ---------------------------------------------------------------------------
505→// Process a single uncovered cluster: classify and propose or observe
506→// ---------------------------------------------------------------------------
507→
508→async function processUncoveredCluster(
509→  surreal: Surreal,
510→  workspaceRecord: RecordId<"workspace", string>,
511→  model: LanguageModel,
512→  cluster: ObservationCluster,
513→  existingLearnings: string[],
514→  embeddingModel?: EmbeddingModel,
515→  embeddingDimension?: number,
516→): Promise<{ proposed: boolean }> {
517→  const classification = await classifyRootCause(model, cluster, existingLearnings);
518→
519→  if (!classification) {
520→    logInfo("observer.learning.classification_skipped", "Skipping cluster due to failed LLM classification", {
521→      clusterSize: cluster.clusterSize,
522→      representativeText: cluster.representativeText.slice(0, 100),
523→    });
524→    return { proposed: false };
525→  }
526→
527→  if (shouldProposeLearning(classification)) {
528→    const learningInput = rootCauseToLearningInput(classification, cluster);
529→
530→    // Generate embedding for the proposed learning text to enable
531→    // dismissed similarity gate and persist with the learning record
532→    const embedding = embeddingModel && embeddingDimension
533→      ? await createEmbeddingVector(embeddingModel, learningInput.text, embeddingDimension)
534→      : undefined;
535→
536→    const result = await suggestLearning({
537→      surreal,
538→      workspaceRecord,
539→      learning: learningInput,
540→      embedding,
541→      now: new Date(),
542→    });
543→
544→    if (result.created) {
545→      logInfo("observer.learning.proposed", "Learning proposed from root cause analysis", {
546→        category: classification.category,
547→        confidence: classification.confidence,
548→        learningType: classification.proposed_learning_type,
549→        learningId: result.learningRecord.id,
550→      });
551→      return { proposed: true };
552→    }
553→
554→    logInfo("observer.learning.gate_blocked", "Learning proposal blocked by safety gate", {
555→      reason: result.reason,
556→    });
557→    return { proposed: false };
558→  }
559→
560→  // Dual gate failed: create an observation instead
561→  await createObservation({
562→    surreal,
563→    workspaceRecord,
564→    text: `Emerging pattern detected but root cause unclear (${classification.category}, confidence: ${classification.confidence.toFixed(2)}): ${classification.reasoning}`,
565→    severity: "info",
566→    sourceAgent: "observer_agent",
567→    observationType: "pattern",
568→    now: new Date(),
569→  });
570→
571→  logInfo("observer.learning.low_confidence", "Pattern observed but confidence too low for learning proposal", {
572→    category: classification.category,
573→    confidence: classification.confidence,
574→    shouldPropose: classification.should_propose_learning,
575→  });
576→
577→  return { proposed: false };
578→}
