  1→/**
  2→ * Pattern Detection Module
  3→ *
  4→ * Rate limiting gate and dismissed re-suggestion prevention for agent-suggested learnings.
  5→ * Pure functions that compose query results into blocking/allow decisions.
  6→ */
  7→import { RecordId, type Surreal } from "surrealdb";
  8→import { countRecentSuggestionsByAgent, createLearning } from "./queries";
  9→import { cosineSimilarity } from "../graph/embeddings";
 10→import { logInfo } from "../http/observability";
 11→import type { CreateLearningInput, LearningRecord } from "./types";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Result types
 15→// ---------------------------------------------------------------------------
 16→
 17→export type RateLimitResult =
 18→  | { blocked: false; count: number }
 19→  | { blocked: true; count: number };
 20→
 21→export type DismissedSimilarityResult =
 22→  | { blocked: false }
 23→  | { blocked: true; matchedText: string };
 24→
 25→export type SuggestLearningResult =
 26→  | { created: true; learningRecord: LearningRecord }
 27→  | { created: false; reason: "rate_limited"; count: number }
 28→  | { created: false; reason: "dismissed_similarity"; matchedText: string };
 29→
 30→// ---------------------------------------------------------------------------
 31→// Rate limit check
 32→// ---------------------------------------------------------------------------
 33→
 34→const RATE_LIMIT_MAX = 5;
 35→
 36→export async function checkRateLimit(input: {
 37→  surreal: Surreal;
 38→  workspaceRecord: RecordId<"workspace", string>;
 39→  agentType: string;
 40→}): Promise<RateLimitResult> {
 41→  const count = await countRecentSuggestionsByAgent({
 42→    surreal: input.surreal,
 43→    workspaceRecord: input.workspaceRecord,
 44→    agentType: input.agentType,
 45→  });
 46→
 47→  return count >= RATE_LIMIT_MAX
 48→    ? { blocked: true, count }
 49→    : { blocked: false, count };
 50→}
 51→
 52→// ---------------------------------------------------------------------------
 53→// Dismissed similarity check (KNN two-step pattern)
 54→// ---------------------------------------------------------------------------
 55→
 56→// Higher than collision thresholds (0.75 learning, 0.40 policy, 0.55 decision)
 57→// because dismissed re-suggestion must be near-identical to the original --
 58→// a slightly different learning on the same topic should still be allowed.
 59→const DISMISSED_SIMILARITY_THRESHOLD = 0.85;
 60→
 61→export async function checkDismissedSimilarity(input: {
 62→  surreal: Surreal;
 63→  workspaceRecord: RecordId<"workspace", string>;
 64→  proposedEmbedding: number[];
 65→}): Promise<DismissedSimilarityResult> {
 66→  // Step 1: KNN candidates (HNSW index only)
 67→  // Step 2: Filter by workspace + dismissed status + similarity threshold
 68→  // Two-step KNN pattern: LET is index 0 (undefined), SELECT is index 1
 69→  const results = await input.surreal
 70→    .query<[undefined, Array<{ text: string; similarity: number }>]>(
 71→      [
 72→        "LET $candidates = SELECT id, text, workspace, status,",
 73→        "vector::similarity::cosine(embedding, $embedding) AS similarity",
 74→        "FROM learning WHERE embedding <|10, COSINE|> $embedding;",
 75→        "SELECT text, similarity FROM $candidates",
 76→        `WHERE workspace = $ws AND status = "dismissed" AND similarity > ${DISMISSED_SIMILARITY_THRESHOLD}`,
 77→        "ORDER BY similarity DESC LIMIT 1;",
 78→      ].join("\n"),
 79→      {
 80→        embedding: input.proposedEmbedding,
 81→        ws: input.workspaceRecord,
 82→      },
 83→    );
 84→
 85→  const matches = results[1] ?? [];
 86→  const match = matches[0];
 87→  if (match) {
 88→    return { blocked: true, matchedText: match.text };
 89→  }
 90→
 91→  // Fallback: brute-force scan when HNSW index hasn't indexed recent inserts.
 92→  const [dismissedLearnings] = await input.surreal.query<[Array<{ text: string; embedding: number[] }>]>(
 93→    `SELECT text, embedding FROM learning
 94→     WHERE workspace = $ws
 95→       AND status = "dismissed"
 96→       AND embedding IS NOT NONE;`,
 97→    { ws: input.workspaceRecord },
 98→  );
 99→
100→  for (const learning of dismissedLearnings ?? []) {
101→    const similarity = cosineSimilarity(input.proposedEmbedding, learning.embedding);
102→    logInfo("learning.dismissed.similarity_check", "Dismissed similarity check", {
103→      similarity,
104→      threshold: DISMISSED_SIMILARITY_THRESHOLD,
105→      dismissedText: learning.text.slice(0, 80),
106→    });
107→    if (similarity > DISMISSED_SIMILARITY_THRESHOLD) {
108→      return { blocked: true, matchedText: learning.text };
109→    }
110→  }
111→
112→  return { blocked: false };
113→}
114→
115→// ---------------------------------------------------------------------------
116→// Suggest learning (orchestrates gates then creates)
117→// ---------------------------------------------------------------------------
118→
119→export async function suggestLearning(input: {
120→  surreal: Surreal;
121→  workspaceRecord: RecordId<"workspace", string>;
122→  learning: CreateLearningInput;
123→  embedding?: number[];
124→  now: Date;
125→}): Promise<SuggestLearningResult> {
126→  const agentType = input.learning.suggestedBy ?? "unknown_agent";
127→
128→  // Gate 1: Rate limit
129→  const rateLimit = await checkRateLimit({
130→    surreal: input.surreal,
131→    workspaceRecord: input.workspaceRecord,
132→    agentType,
133→  });
134→
135→  if (rateLimit.blocked) {
136→    return { created: false, reason: "rate_limited", count: rateLimit.count };
