  1→/**
  2→ * Graph scan: periodic workspace-wide analysis for contradictions and anomalies.
  3→ *
  4→ * Pure query functions that gather scan signals from the workspace graph,
  5→ * then delegate to the observer agent for contradiction analysis.
  6→ *
  7→ * Scan types:
  8→ *   1. Decision-implementation contradictions: confirmed decisions vs completed tasks
  9→ *   2. Stale blocked tasks: tasks blocked longer than threshold (14 days)
 10→ */
 11→
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { LanguageModel, embed } from "ai";
 14→import { createObservation, listWorkspaceOpenObservations, type ObserveTargetRecord } from "../observation/queries";
 15→import { logInfo } from "../http/observability";
 16→import { detectContradictions, evaluateAnomalies, synthesizePatterns, type Anomaly, type AnomalyCandidate } from "./llm-synthesis";
 17→import { parseEntityRef } from "./evidence-validator";
 18→import { runDiagnosticClustering } from "./learning-diagnosis";
 19→
 20→type EmbeddingModel = Parameters<typeof embed>[0]["model"];
 21→
 22→// ---------------------------------------------------------------------------
 23→// Types
 24→// ---------------------------------------------------------------------------
 25→
 26→export type ConfirmedDecision = {
 27→  id: RecordId<"decision">;
 28→  summary: string;
 29→  rationale?: string;
 30→};
 31→
 32→export type CompletedTask = {
 33→  id: RecordId<"task">;
 34→  title: string;
 35→  description?: string;
 36→};
 37→
 38→export type StaleBlockedTask = {
 39→  id: RecordId<"task">;
 40→  title: string;
 41→  description?: string;
 42→  updated_at: string | Date;
 43→  daysBlocked: number;
 44→};
 45→
 46→export type StatusDriftTask = {
 47→  id: RecordId<"task">;
 48→  title: string;
 49→  status: string;
 50→  dependency: {
 51→    id: RecordId<"task">;
 52→    title: string;
 53→    status: string;
 54→  };
 55→};
 56→
 57→export type GraphScanResult = {
 58→  contradictions_found: number;
 59→  stale_blocked_found: number;
 60→  status_drift_found: number;
 61→  observations_created: number;
 62→  llm_filtered_count: number;
 63→  learning_proposals_created: number;
 64→  clusters_found: number;
 65→  coverage_skips: number;
 66→};
