 68→// ---------------------------------------------------------------------------
 69→// Configuration
 70→// ---------------------------------------------------------------------------
 71→
 72→const STALE_BLOCKED_THRESHOLD_DAYS = 14;
 73→
 74→// ---------------------------------------------------------------------------
 75→// Graph queries (pure data gathering)
 76→// ---------------------------------------------------------------------------
 77→
 78→async function queryConfirmedDecisions(
 79→  surreal: Surreal,
 80→  workspaceRecord: RecordId<"workspace", string>,
 81→): Promise<ConfirmedDecision[]> {
 82→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
 83→    `SELECT id, summary, rationale, created_at FROM decision
 84→     WHERE workspace = $ws AND status = "confirmed"
 85→     ORDER BY created_at DESC
 86→     LIMIT 50;`,
 87→    { ws: workspaceRecord },
 88→  );
 89→  return rows ?? [];
 90→}
 91→
 92→async function queryCompletedTasks(
 93→  surreal: Surreal,
 94→  workspaceRecord: RecordId<"workspace", string>,
 95→): Promise<CompletedTask[]> {
 96→  const [rows] = await surreal.query<[CompletedTask[]]>(
 97→    `SELECT id, title, description, updated_at FROM task
 98→     WHERE workspace = $ws AND status IN ["completed", "done"]
 99→     ORDER BY updated_at DESC
100→     LIMIT 50;`,
101→    { ws: workspaceRecord },
102→  );
103→  return rows ?? [];
104→}
105→
106→async function queryStaleBlockedTasks(
107→  surreal: Surreal,
108→  workspaceRecord: RecordId<"workspace", string>,
109→): Promise<StaleBlockedTask[]> {
110→  const thresholdDate = new Date(
111→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
112→  );
113→
114→  const [rows] = await surreal.query<
115→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
116→  >(
117→    `SELECT id, title, description, updated_at FROM task
118→     WHERE workspace = $ws
119→       AND status = "blocked"
120→       AND updated_at < $threshold
121→     ORDER BY updated_at ASC
122→     LIMIT 50;`,
123→    { ws: workspaceRecord, threshold: thresholdDate },
124→  );
125→
126→  return (rows ?? []).map((row) => {
127→    const updatedAt = new Date(row.updated_at);
128→    const daysBlocked = Math.floor(
129→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
130→    );
131→    return { ...row, daysBlocked };
132→  });
133→}
134→
135→async function queryStatusDriftTasks(
136→  surreal: Surreal,
137→  workspaceRecord: RecordId<"workspace", string>,
138→): Promise<StatusDriftTask[]> {
139→  // Two-step approach: first find completed tasks with dependencies,
140→  // then filter for incomplete dependencies in application code
141→  const [rows] = await surreal.query<[Array<{
142→    id: RecordId<"task">;
143→    title: string;
144→    status: string;
145→    dep_ids: RecordId<"task">[];
146→    dep_titles: string[];
147→    dep_statuses: string[];
148→  }>]>(
149→    `SELECT
150→       id, title, status,
151→       ->depends_on->task.id AS dep_ids,
152→       ->depends_on->task.title AS dep_titles,
153→       ->depends_on->task.status AS dep_statuses
154→     FROM task
155→     WHERE workspace = $ws
156→       AND status IN ["completed", "done"]
157→       AND array::len(->depends_on->task) > 0
158→     LIMIT 50;`,
159→    { ws: workspaceRecord },
160→  );
161→
162→  return (rows ?? []).flatMap((row) => {
163→    const depIds = row.dep_ids ?? [];
164→    const depTitles = row.dep_titles ?? [];
165→    const depStatuses = row.dep_statuses ?? [];
166→
167→    const drifts: StatusDriftTask[] = [];
168→    for (let i = 0; i < depIds.length; i++) {
169→      const depStatus = depStatuses[i];
170→      if (depStatus !== "completed" && depStatus !== "done") {
171→        drifts.push({
172→          id: row.id,
173→          title: row.title,
174→          status: row.status,
175→          dependency: {
176→            id: depIds[i],
177→            title: depTitles[i],
178→            status: depStatus,
179→          },
180→        });
181→      }
182→    }
183→    return drifts;
184→  });
185→}
