187→// ---------------------------------------------------------------------------
188→// Entity-level deduplication query
189→// ---------------------------------------------------------------------------
190→
191→/**
192→ * Queries existing open observer observations linked to a specific entity.
193→ * Used for entity-level dedup -- if the observer already has an open observation
194→ * on this entity, we skip creating another.
195→ */
196→// Static query map: one pre-built query string per allowed table, eliminating
197→// dynamic interpolation at the call site (prevents SurrealQL injection).
198→const OBSERVER_DEDUP_QUERIES: Record<string, string> = Object.fromEntries(
199→  ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation"].map(
200→    (table) => [
201→      table,
202→      `SELECT text, severity, status FROM observation
203→       WHERE workspace = $ws
204→         AND source_agent = "observer_agent"
205→         AND status IN ["open", "acknowledged"]
206→         AND ->observes->${table}.id CONTAINS $entity
207→       LIMIT 20;`,
208→    ],
209→  ),
210→);
211→
212→export async function queryExistingObserverObservationsForEntity(
213→  surreal: Surreal,
214→  workspaceRecord: RecordId<"workspace", string>,
215→  entityRecord: RecordId<string, string>,
216→): Promise<Array<{ text: string; severity: string; status: string }>> {
217→  const query = OBSERVER_DEDUP_QUERIES[entityRecord.table.name];
218→  if (!query) {
219→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
220→  }
221→
222→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
223→    query,
224→    { ws: workspaceRecord, entity: entityRecord },
225→  );
226→  return rows ?? [];
227→}
228→
229→// ---------------------------------------------------------------------------
230→// Deduplication
231→// ---------------------------------------------------------------------------
232→
233→type ExistingObservation = {
234→  text: string;
235→  severity: string;
236→  status: string;
237→};
238→
239→function isAlreadyObserved(
240→  existingObservations: ExistingObservation[],
241→  newText: string,
242→  entityId?: string,
243→): boolean {
244→  const normalizedNew = newText.toLowerCase();
245→
246→  return existingObservations.some((obs) => {
247→    if (obs.status === "resolved") return false;
248→
249→    // When entity ID is available, require it to appear in the existing text
250→    // so observations about different entities are never considered duplicates
251→    if (entityId && !obs.text.toLowerCase().includes(entityId.toLowerCase())) {
252→      return false;
253→    }
254→
255→    const normalizedExisting = obs.text.toLowerCase();
256→    // Check if the core issue is already covered using a meaningful prefix
257→    const prefixLen = Math.min(80, normalizedNew.length);
258→    return (
259→      normalizedExisting.includes(normalizedNew.slice(0, prefixLen)) ||
260→      normalizedNew.includes(normalizedExisting.slice(0, prefixLen))
261→    );
262→  });
263→}
264→
265→// ---------------------------------------------------------------------------
266→// Scan orchestrator
267→// ---------------------------------------------------------------------------
268→
269→export async function runGraphScan(
270→  surreal: Surreal,
271→  workspaceRecord: RecordId<"workspace", string>,
272→  observerModel: LanguageModel,
273→  embeddingModel: EmbeddingModel,
274→  embeddingDimension: number,
275→): Promise<GraphScanResult> {
276→  const result: GraphScanResult = {
277→    contradictions_found: 0,
278→    stale_blocked_found: 0,
279→    status_drift_found: 0,
280→    observations_created: 0,
281→    llm_filtered_count: 0,
282→    learning_proposals_created: 0,
283→    clusters_found: 0,
284→    coverage_skips: 0,
285→  };
286→
287→  // Load existing observations for deduplication
288→  const existingObservations = await listWorkspaceOpenObservations({
289→    surreal,
290→    workspaceRecord,
291→    limit: 100,
292→  });
293→
294→  // 1. Detect decision-implementation contradictions (LLM-based)
295→  const [decisions, completedTasks] = await Promise.all([
296→    queryConfirmedDecisions(surreal, workspaceRecord),
297→    queryCompletedTasks(surreal, workspaceRecord),
298→  ]);
299→
300→  type ContradictionPair = { decision: ConfirmedDecision; task: CompletedTask };
301→  const contradictions: ContradictionPair[] = [];
302→
303→  if (decisions.length > 0 && completedTasks.length > 0) {
304→    const decisionMap = new Map(decisions.map((d) => [d.id.id as string, d]));
305→    const taskMap = new Map(completedTasks.map((t) => [t.id.id as string, t]));
306→
307→    const detected = await detectContradictions(
308→      observerModel,
309→      decisions.map((d) => ({ id: d.id.id as string, summary: d.summary, rationale: d.rationale })),
310→      completedTasks.map((t) => ({ id: t.id.id as string, title: t.title, description: t.description })),
311→    );
312→
313→    if (detected) {
314→      for (const c of detected) {
315→        const decisionId = parseEntityRef(c.decision_ref)?.id;
316→        const taskId = parseEntityRef(c.task_ref)?.id;
317→        const decision = decisionId ? decisionMap.get(decisionId) : undefined;
318→        const task = taskId ? taskMap.get(taskId) : undefined;
319→        if (decision && task) contradictions.push({ decision, task });
320→      }
321→    }
322→  }
323→
324→  result.contradictions_found = contradictions.length;
325→
326→  for (const { decision, task } of contradictions) {
327→    // Entity-level dedup: check if observer already has an open observation on this decision
328→    const existingForDecision = await queryExistingObserverObservationsForEntity(
329→      surreal, workspaceRecord,
330→      decision.id as RecordId<string, string>,
331→    );
332→
333→    const observationText =
334→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
335→      `The task appears to implement an approach that contradicts the confirmed decision.`;
336→
337→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText, decision.id.id as string)) {
338→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
339→        decisionId: decision.id.id,
340→        taskId: task.id.id,
341→      });
342→      continue;
343→    }
344→
345→    const now = new Date();
346→    await createObservation({
347→      surreal,
348→      workspaceRecord,
349→      text: observationText,
350→      severity: "conflict",
351→      sourceAgent: "observer_agent",
352→      observationType: "contradiction",
353→      now,
354→      relatedRecords: [
355→        decision.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
356→        task.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
357→      ],
358→    });
359→
360→    result.observations_created += 1;
361→  }
362→
363→  // 2. Detect stale blocked tasks and status drift (concurrent queries)
364→  const [staleBlocked, driftTasks] = await Promise.all([
365→    queryStaleBlockedTasks(surreal, workspaceRecord),
366→    queryStatusDriftTasks(surreal, workspaceRecord),
367→  ]);
368→  result.stale_blocked_found = staleBlocked.length;
369→  result.status_drift_found = driftTasks.length;
370→
371→  // 3. LLM anomaly evaluation: filter false positives before creating observations
372→  const anomalyCandidates: AnomalyCandidate[] = [];
373→
374→  for (const task of staleBlocked) {
375→    anomalyCandidates.push({
376→      entityRef: `task:${task.id.id as string}`,
377→      type: "stale_blocked",
378→      title: task.title,
379→      description: task.description,
380→      detail: `Blocked for ${task.daysBlocked} days since ${new Date(task.updated_at).toISOString().slice(0, 10)}`,
381→    });
382→  }
383→
384→  for (const drift of driftTasks) {
385→    anomalyCandidates.push({
386→      entityRef: `task:${drift.id.id as string}`,
387→      type: "status_drift",
388→      title: drift.title,
389→      description: undefined,
390→      detail: `Marked as ${drift.status} but dependency "${drift.dependency.title}" is still ${drift.dependency.status}`,
391→    });
392→  }
393→
394→  // Build evaluation map: entityRef -> LLM verdict (fallback: all relevant with default severity)
395→  const evaluationMap = new Map<string, { relevant: boolean; reasoning: string; severity: "info" | "warning" | "conflict" }>();
396→
397→  if (anomalyCandidates.length > 0) {
398→    const evaluations = await evaluateAnomalies(observerModel, anomalyCandidates);
399→
400→    if (evaluations) {
401→      for (const ev of evaluations) {
402→        evaluationMap.set(ev.entity_ref, {
403→          relevant: ev.relevant,
404→          reasoning: ev.reasoning,
405→          severity: ev.suggested_severity,
406→        });
407→      }
408→    } else {
409→      logInfo("observer.llm.fallback", "Anomaly evaluation failed, treating all as relevant", {
410→        candidateCount: anomalyCandidates.length,
411→      });
412→    }
413→  }
414→
415→  // Create observations for anomalies (stale-blocked + status-drift), LLM-filtered
416→  type AnomalyObservation = {
417→    entityRef: string;
418→    taskRecord: RecordId<"task">;
419→    observationText: string;
420→    anomalyType: string;
421→    dedupContext?: Record<string, unknown>;
422→  };
423→
424→  const anomalyObservations: AnomalyObservation[] = [];
425→
426→  for (const task of staleBlocked) {
427→    const llmReasoning = evaluationMap.get(`task:${task.id.id as string}`)?.reasoning;
428→    anomalyObservations.push({
429→      entityRef: `task:${task.id.id as string}`,
430→      taskRecord: task.id,
431→      anomalyType: "stale-blocked",
432→      observationText: llmReasoning
433→        ? `Task blocked for ${task.daysBlocked} days: "${task.title}". ${llmReasoning}`
434→        : `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
435→          `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
436→          `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`,
437→      dedupContext: { taskId: task.id.id },
438→    });
439→  }
440→
441→  for (const drift of driftTasks) {
442→    const llmReasoning = evaluationMap.get(`task:${drift.id.id as string}`)?.reasoning;
443→    anomalyObservations.push({
444→      entityRef: `task:${drift.id.id as string}`,
445→      taskRecord: drift.id,
446→      anomalyType: "status-drift",
447→      observationText: llmReasoning
448→        ? `Status drift: Task "${drift.title}" is ${drift.status} but dependency "${drift.dependency.title}" is ${drift.dependency.status}. ${llmReasoning}`
449→        : `Status drift detected: Task "${drift.title}" is marked as ${drift.status}, ` +
450→          `but its dependency "${drift.dependency.title}" is still ${drift.dependency.status}. ` +
451→          `A task should not be completed before its dependencies.`,
452→      dedupContext: { taskId: drift.id.id, depTaskId: drift.dependency.id.id },
453→    });
454→  }
455→
456→  for (const anomaly of anomalyObservations) {
457→    const evaluation = evaluationMap.get(anomaly.entityRef);
458→
459→    if (evaluation && !evaluation.relevant) {
460→      logInfo("observer.scan.llm_filtered", `${anomaly.anomalyType} task filtered by LLM as not relevant`, {
461→        taskId: (anomaly.taskRecord.id as string),
462→        reasoning: evaluation.reasoning,
463→      });
464→      result.llm_filtered_count += 1;
465→      continue;
466→    }
467→
468→    const existingForTask = await queryExistingObserverObservationsForEntity(
469→      surreal, workspaceRecord,
470→      anomaly.taskRecord as RecordId<string, string>,
471→    );
472→
473→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, anomaly.observationText, anomaly.taskRecord.id as string)) {
474→      logInfo("observer.scan.dedup", `Skipping duplicate ${anomaly.anomalyType} observation`, anomaly.dedupContext ?? {});
475→      continue;
476→    }
477→
478→    const severity = evaluation?.severity ?? "warning";
479→    const now = new Date();
480→    await createObservation({
481→      surreal,
482→      workspaceRecord,
483→      text: anomaly.observationText,
484→      severity,
485→      sourceAgent: "observer_agent",
486→      observationType: "anomaly",
487→      now,
488→      relatedRecords: [anomaly.taskRecord as RecordId<"project" | "feature" | "task" | "decision" | "question", string>],
489→    });
490→
491→    result.observations_created += 1;
492→  }
493→
494→  // 4. LLM pattern synthesis
495→  const anomalies: Anomaly[] = [];
496→
497→  for (const { decision, task } of contradictions) {
498→    anomalies.push({
499→      type: "contradiction",
500→      text: `Decision "${decision.summary}" conflicts with task "${task.title}"`,
501→      entityId: decision.id.id as string,
502→      entityTable: "decision",
503→    });
504→    anomalies.push({
505→      type: "contradiction",
506→      text: `Task "${task.title}" contradicts decision "${decision.summary}"`,
507→      entityId: task.id.id as string,
508→      entityTable: "task",
509→    });
510→  }
511→  for (const task of staleBlocked) {
512→    const evaluation = evaluationMap.get(`task:${task.id.id as string}`);
513→    if (evaluation && !evaluation.relevant) continue; // skip LLM-filtered anomalies
514→    anomalies.push({
515→      type: "stale_blocked",
516→      text: `Task "${task.title}" blocked for ${task.daysBlocked} days`,
517→      entityId: task.id.id as string,
518→      entityTable: "task",
519→    });
520→  }
521→  for (const drift of driftTasks) {
522→    const evaluation = evaluationMap.get(`task:${drift.id.id as string}`);
523→    if (evaluation && !evaluation.relevant) continue; // skip LLM-filtered anomalies
524→    anomalies.push({
525→      type: "status_drift",
526→      text: `Task "${drift.title}" completed but dependency "${drift.dependency.title}" is ${drift.dependency.status}`,
527→      entityId: drift.id.id as string,
528→      entityTable: "task",
529→    });
530→  }
531→
532→  if (anomalies.length > 0) {
533→    const patterns = await synthesizePatterns(observerModel, anomalies);
534→
535→    if (patterns) {
536→      for (const pattern of patterns) {
537→        // Dedup: check if a similar pattern observation already exists
538→        const patternText = `${pattern.pattern_name}: ${pattern.description}`;
539→        if (isAlreadyObserved(existingObservations, patternText)) {
540→          logInfo("observer.scan.synthesis_dedup", "Skipping duplicate pattern", {
541→            pattern: pattern.pattern_name,
542→          });
543→          continue;
544→        }
545→
546→        // Build related records from contributing entities
547→        const relatedRecords: ObserveTargetRecord[] = [];
548→        for (const ref of pattern.contributing_entities) {
549→          const parsed = parseEntityRef(ref);
550→          if (parsed) {
551→            relatedRecords.push(new RecordId(parsed.table, parsed.id) as ObserveTargetRecord);
552→          }
553→        }
554→
555→        const now = new Date();
556→        await createObservation({
557→          surreal,
558→          workspaceRecord,
559→          text: patternText,
560→          severity: pattern.severity,
561→          sourceAgent: "observer_agent",
562→          observationType: "pattern",
563→          now,
564→          relatedRecords: relatedRecords.length > 0 ? relatedRecords : undefined,
565→        });
566→
567→        result.observations_created += 1;
568→      }
569→
570→      logInfo("observer.scan.synthesis", "Pattern synthesis completed", {
571→        patternsFound: patterns.length,
572→      });
573→    } else {
574→      logInfo("observer.llm.fallback", "Pattern synthesis failed, anomalies reported individually", {
575→        anomalyCount: anomalies.length,
576→      });
577→    }
578→  }
579→
580→  // 5. Diagnostic learning proposals: cluster observations and check coverage
581→  try {
582→    const diagnostic = await runDiagnosticClustering(surreal, workspaceRecord, observerModel, embeddingModel, embeddingDimension);
583→    result.clusters_found = diagnostic.result.clusters_found;
584→    result.coverage_skips = diagnostic.result.coverage_skips;
585→    result.learning_proposals_created = diagnostic.result.learning_proposals_created;
586→
587→    logInfo("observer.scan.diagnostic", "Diagnostic clustering completed", {
588→      workspaceId: workspaceRecord.id,
589→      clustersFound: diagnostic.result.clusters_found,
590→      coverageSkips: diagnostic.result.coverage_skips,
591→      uncoveredClusters: diagnostic.uncoveredClusters.length,
592→    });
593→  } catch (error) {
594→    logInfo("observer.scan.diagnostic_error", "Diagnostic clustering failed, continuing scan", {
595→      workspaceId: workspaceRecord.id,
596→      error: error instanceof Error ? error.message : String(error),
597→    });
598→  }
599→
600→  logInfo("observer.scan.completed", "Graph scan completed", {
601→    workspaceId: workspaceRecord.id,
602→    ...result,
603→  });
604→
605→  return result;
606→}
