707→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
708→  LET $query = string::lowercase(string::trim($q));
709→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
710→
711→  LET $task_rows = SELECT
712→    id,
713→    "task" AS kind,
714→    title AS text,
715→    extraction_confidence AS confidence,
716→    source_message AS sourceMessage,
717→    priority,
718→    created_at
719→  FROM task
720→  WHERE workspace = $workspace
721→    AND extraction_confidence != NONE
722→    AND string::contains(string::lowercase(title), $query)
723→  ORDER BY created_at DESC
724→  LIMIT $safe_limit;
725→
726→  LET $decision_rows = SELECT
727→    id,
728→    "decision" AS kind,
729→    summary AS text,
730→    extraction_confidence AS confidence,
731→    source_message AS sourceMessage,
732→    priority,
733→    created_at
734→  FROM decision
735→  WHERE workspace = $workspace
736→    AND extraction_confidence != NONE
737→    AND string::contains(string::lowercase(summary), $query)
738→  ORDER BY created_at DESC
739→  LIMIT $safe_limit;
740→
741→  LET $question_rows = SELECT
742→    id,
743→    "question" AS kind,
744→    text AS text,
745→    extraction_confidence AS confidence,
746→    source_message AS sourceMessage,
747→    priority,
748→    created_at
749→  FROM question
