751→    AND extraction_confidence != NONE
752→    AND string::contains(string::lowercase(text), $query)
753→  ORDER BY created_at DESC
754→  LIMIT $safe_limit;
755→
756→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
