 48→  | { covered: true; matchedLearningText: string; similarity: number };
 49→
 50→export type DiagnosticResult = {
 51→  learning_proposals_created: number;
 52→  coverage_skips: number;
 53→  clusters_found: number;
 54→};
 55→
 56→// ---------------------------------------------------------------------------
 57→// Configuration
 58→// ---------------------------------------------------------------------------
 59→
 60→const CLUSTER_SIMILARITY_THRESHOLD = 0.75;
 61→const MINIMUM_CLUSTER_SIZE = 3;
 62→const TIME_WINDOW_DAYS = 14;
 63→// Coverage threshold is lower than typical dedup thresholds (0.85) because
 64→// we compare observation-text centroids (descriptive, noisy) against learning-text
 65→// embeddings (directive, concise). Cross-form comparisons consistently score
 66→// 30-40% lower on cosine similarity than same-form comparisons.
 67→const COVERAGE_SIMILARITY_THRESHOLD = 0.50;
 68→// Same cross-domain text form issue as coverage threshold — observation
 69→// centroids vs dismissed learning embeddings. Lower than the dismissed
 70→// re-suggestion gate (0.85) in suggestLearning() which compares same-form texts.
 71→const DISMISSED_PATTERN_SIMILARITY_THRESHOLD = 0.50;
 72→
 73→// ---------------------------------------------------------------------------
 74→// Observation query (IO boundary)
 75→// ---------------------------------------------------------------------------
 76→
 77→/**
 78→ * Queries open/acknowledged observations from the past 14 days with embeddings.
 79→ * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug.
 80→ */
 81→export async function queryRecentObservationsWithEmbeddings(
 82→  surreal: Surreal,
 83→  workspaceRecord: RecordId<"workspace", string>,
 84→): Promise<ObservationWithEmbedding[]> {
 85→  const cutoff = new Date(Date.now() - TIME_WINDOW_DAYS * 24 * 60 * 60 * 1000);
 86→
 87→  const [rows] = await surreal.query<[Array<{
 88→    id: RecordId<"observation">;
 89→    text: string;
 90→    severity: string;
 91→    embedding: number[];
 92→    entity_refs: Array<RecordId | string>;
 93→    created_at: string;
 94→  }>]>(
 95→    `SELECT id, text, severity, embedding, created_at,
 96→            ->observes->task.id AS entity_refs
 97→     FROM observation
 98→     WHERE workspace = $ws
 99→       AND status IN ["open", "acknowledged"]
100→       AND created_at > $cutoff
101→       AND embedding IS NOT NONE
102→     ORDER BY created_at DESC
103→     LIMIT 200;`,
104→    { ws: workspaceRecord, cutoff },
105→  );
106→
107→  return (rows ?? []).map((row) => ({
108→    id: row.id.id as string,
109→    text: row.text,
110→    severity: row.severity,
111→    embedding: row.embedding,
112→    entityRefs: (row.entity_refs ?? [])
113→      .filter((ref): ref is RecordId => typeof ref === "object" && ref !== null && "id" in ref)
114→      .map((ref) => `task:${ref.id as string}`),
115→  }));
116→}
117→
118→// ---------------------------------------------------------------------------
119→// Pure clustering (no IO)
120→// ---------------------------------------------------------------------------
121→
122→/**
123→ * Clusters observations by pairwise embedding similarity using single-linkage.
124→ *
125→ * Algorithm:
126→ * 1. Build adjacency: observation A is neighbor of B if similarity > threshold
127→ * 2. Connected components via BFS form clusters
128→ * 3. Filter clusters by minimum size
129→ *
130→ * Pure function -- no IO.
131→ */
132→export function clusterObservationsBySimilarity(
133→  observations: ObservationWithEmbedding[],
134→  similarityThreshold: number = CLUSTER_SIMILARITY_THRESHOLD,
135→  minimumClusterSize: number = MINIMUM_CLUSTER_SIZE,
136→): ObservationCluster[] {
137→  if (observations.length < minimumClusterSize) return [];
138→
139→  // Build adjacency list
140→  const adjacency = new Map<number, Set<number>>();
141→  for (let i = 0; i < observations.length; i++) {
142→    adjacency.set(i, new Set());
143→  }
144→
145→  for (let i = 0; i < observations.length; i++) {
146→    for (let j = i + 1; j < observations.length; j++) {
147→      const similarity = cosineSimilarity(
148→        observations[i].embedding,
149→        observations[j].embedding,
150→      );
151→      if (similarity > similarityThreshold) {
152→        adjacency.get(i)!.add(j);
153→        adjacency.get(j)!.add(i);
154→      }
155→    }
156→  }
157→
158→  // BFS to find connected components
159→  const visited = new Set<number>();
160→  const clusters: ObservationCluster[] = [];
161→
162→  for (let i = 0; i < observations.length; i++) {
163→    if (visited.has(i)) continue;
164→
165→    const component: number[] = [];
166→    const queue = [i];
167→    visited.add(i);
168→
169→    while (queue.length > 0) {
170→      const current = queue.shift()!;
171→      component.push(current);
172→
173→      for (const neighbor of adjacency.get(current)!) {
174→        if (!visited.has(neighbor)) {
175→          visited.add(neighbor);
176→          queue.push(neighbor);
177→        }
178→      }
179→    }
180→
181→    if (component.length >= minimumClusterSize) {
182→      const clusterObservations = component.map((idx) => ({
183→        id: observations[idx].id,
184→        text: observations[idx].text,
185→        severity: observations[idx].severity,
186→        entityRefs: observations[idx].entityRefs,
187→      }));
188→
189→      // Representative text: the observation with highest average similarity to others in cluster
190→      const representativeIndex = pickRepresentativeIndex(component, observations);
191→
192→      clusters.push({
193→        observations: clusterObservations,
194→        representativeText: observations[representativeIndex].text,
195→        clusterSize: component.length,
196→      });
197→    }
198→  }
199→
200→  return clusters;
201→}
202→
203→/**
204→ * Computes the centroid (element-wise average) of a set of embedding vectors.
205→ * This reduces noise from individual observation text variations, producing
206→ * a more representative embedding for cluster-level similarity comparisons.
207→ */
208→function computeCentroidEmbedding(embeddings: number[][]): number[] {
209→  if (embeddings.length === 0) return [];
210→  if (embeddings.length === 1) return embeddings[0];
211→
212→  const dimension = embeddings[0].length;
213→  const centroid = new Array<number>(dimension).fill(0);
214→
215→  for (const embedding of embeddings) {
216→    for (let i = 0; i < dimension; i++) {
217→      centroid[i] += embedding[i];
218→    }
219→  }
220→
221→  for (let i = 0; i < dimension; i++) {
222→    centroid[i] /= embeddings.length;
223→  }
224→
225→  return centroid;
226→}
227→
228→/**
229→ * Picks the observation with highest average similarity to other cluster members.
230→ */
231→function pickRepresentativeIndex(
232→  componentIndices: number[],
233→  observations: ObservationWithEmbedding[],
234→): number {
235→  let bestIndex = componentIndices[0];
236→  let bestAvgSimilarity = -1;
237→
238→  for (const i of componentIndices) {
239→    let totalSimilarity = 0;
240→    for (const j of componentIndices) {
241→      if (i !== j) {
242→        totalSimilarity += cosineSimilarity(
243→          observations[i].embedding,
244→          observations[j].embedding,
245→        );
246→      }
247→    }
248→    const avgSimilarity = totalSimilarity / (componentIndices.length - 1);
249→    if (avgSimilarity > bestAvgSimilarity) {
250→      bestAvgSimilarity = avgSimilarity;
251→      bestIndex = i;
252→    }
253→  }
254→
255→  return bestIndex;
256→}
257→
258→// ---------------------------------------------------------------------------
259→// Coverage check (IO boundary -- KNN query)
260→// ---------------------------------------------------------------------------
261→
262→/**
263→ * Checks if any learning with a given status covers the cluster pattern.
264→ * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug, with brute-force fallback.
265→ */
266→async function checkLearningCoverage(
267→  surreal: Surreal,
268→  workspaceRecord: RecordId<"workspace", string>,
269→  clusterEmbedding: number[],
270→  learningStatus: "active" | "dismissed",
271→  similarityThreshold: number,
272→): Promise<CoverageCheckResult> {
273→  const results = await surreal
274→    .query<[undefined, Array<{ text: string; similarity: number }>]>(
275→      [
276→        "LET $candidates = SELECT id, text, workspace, status,",
277→        "vector::similarity::cosine(embedding, $embedding) AS similarity",
278→        "FROM learning WHERE embedding <|10, COSINE|> $embedding;",
279→        "SELECT text, similarity FROM $candidates",
280→        "WHERE workspace = $ws AND status = $status AND similarity > $threshold",
281→        "ORDER BY similarity DESC LIMIT 1;",
282→      ].join("\n"),
283→      {
284→        embedding: clusterEmbedding,
285→        ws: workspaceRecord,
286→        status: learningStatus,
287→        threshold: similarityThreshold,
288→      },
289→    );
290→
291→  const matches = results[1] ?? [];
292→  const match = matches[0];
293→  if (match) {
294→    return { covered: true, matchedLearningText: match.text, similarity: match.similarity };
295→  }
296→
297→  // Brute-force fallback when HNSW index hasn't indexed recent inserts
298→  const [learnings] = await surreal.query<[Array<{ text: string; embedding: number[] }>]>(
299→    `SELECT text, embedding FROM learning
300→     WHERE workspace = $ws
301→       AND status = $status
302→       AND embedding IS NOT NONE;`,
303→    { ws: workspaceRecord, status: learningStatus },
304→  );
305→
306→  if (learningStatus === "active") {
307→    logInfo("observer.learning.coverage_fallback", "Fallback coverage check", {
308→      activeLearningsCount: (learnings ?? []).length,
309→      workspaceId: workspaceRecord.id,
310→    });
311→  }
312→
313→  for (const learning of learnings ?? []) {
314→    const similarity = cosineSimilarity(clusterEmbedding, learning.embedding);
315→    if (similarity > similarityThreshold) {
316→      return { covered: true, matchedLearningText: learning.text, similarity };
317→    }
318→  }
319→
320→  return { covered: false };
321→}
322→
323→export async function checkCoverageAgainstActiveLearnings(
324→  surreal: Surreal,
325→  workspaceRecord: RecordId<"workspace", string>,
326→  clusterEmbedding: number[],
327→): Promise<CoverageCheckResult> {
328→  return checkLearningCoverage(surreal, workspaceRecord, clusterEmbedding, "active", COVERAGE_SIMILARITY_THRESHOLD);
329→}
330→
331→export async function checkDismissedLearningForCluster(
332→  surreal: Surreal,
333→  workspaceRecord: RecordId<"workspace", string>,
334→  clusterEmbedding: number[],
335→): Promise<CoverageCheckResult> {
336→  return checkLearningCoverage(surreal, workspaceRecord, clusterEmbedding, "dismissed", DISMISSED_PATTERN_SIMILARITY_THRESHOLD);
337→}
