339→// ---------------------------------------------------------------------------
340→// Root cause classification (LLM structured output)
341→// ---------------------------------------------------------------------------
342→
343→const CONFIDENCE_THRESHOLD = 0.70;
344→const CLASSIFICATION_TIMEOUT_MS = 30_000;
345→
346→/**
347→ * Builds the LLM prompt for root cause classification.
348→ * Pure function -- formats cluster and context into prompt text.
349→ */
350→function buildClassificationPrompt(
351→  cluster: ObservationCluster,
352→  existingLearnings: string[],
353→): string {
354→  const observationQuotes = cluster.observations
355→    .map((obs, i) => `  ${i + 1}. [${obs.severity}] "${obs.text}"`)
356→    .join("\n");
357→
358→  const entityRefsList = [
359→    ...new Set(cluster.observations.flatMap((obs) => obs.entityRefs)),
360→  ];
361→  const entityRefsText = entityRefsList.length > 0
362→    ? entityRefsList.map((ref) => `  - ${ref}`).join("\n")
363→    : "  No linked entities.";
364→
365→  const learningsText = existingLearnings.length > 0
366→    ? existingLearnings.map((l, i) => `  ${i + 1}. ${l}`).join("\n")
367→    : "  No active learnings.";
368→
369→  return `You are performing root cause analysis on a recurring pattern detected in the workspace.
370→
371→## Pattern Detected
372→Representative text: "${cluster.representativeText}"
373→
374→Observation quotes (${cluster.clusterSize} occurrences):
375→${observationQuotes}
376→
377→## Related Entities
378→${entityRefsText}
379→
380→## Existing Active Learnings
381→${learningsText}
382→
383→## Classification Instructions
384→Determine WHY this pattern keeps recurring:
385→
386→1. Policy Failure: The governance rules allowed something they shouldn't.
387→   -> Propose a constraint that tightens the boundary.
388→
389→2. Context Failure: The agent lacked information it needed to act correctly.
390→   -> Propose an instruction that injects the missing context.
391→
392→3. Behavioral Drift: The agent had the information but didn't apply it.
393→   -> Propose a constraint that reinforces the expected behavior.
394→
395→Set should_propose_learning to true ONLY if:
396→- confidence >= 0.70
397→- You have high conviction in both the category AND the proposed text
398→- The proposed learning is specific enough to be actionable
399→
400→Set should_propose_learning to false if:
401→- The root cause is ambiguous or could fit multiple categories
402→- The proposed learning text is too generic ("be more careful")
403→- The evidence is insufficient to justify a permanent behavioral rule
404→
405→For proposed_learning_type, choose based on the fix needed:
406→- "constraint" for must-follow rules (policy fixes, behavioral reinforcement)
407→- "instruction" for conditional guidance (context injection, situational awareness)
408→
409→In evidence_refs, list the observation IDs in table:id format (e.g. observation:uuid).
410→In target_agents, list the agent types that should receive this learning.`;
411→}
412→
413→/**
414→ * Classifies the root cause of an observation cluster using LLM structured output.
415→ * Returns undefined on any failure (timeout, rate limit, invalid output).
416→ */
417→export async function classifyRootCause(
418→  model: LanguageModel,
419→  cluster: ObservationCluster,
420→  existingLearnings: string[],
421→): Promise<RootCauseClassification | undefined> {
422→  const start = Date.now();
423→
424→  try {
425→    const prompt = buildClassificationPrompt(cluster, existingLearnings);
426→
427→    const result = await generateObject({
428→      model,
429→      system: OBSERVER_IDENTITY,
430→      schema: rootCauseSchema,
431→      prompt,
432→      abortSignal: AbortSignal.timeout(CLASSIFICATION_TIMEOUT_MS),
433→    });
434→
435→    const latencyMs = Date.now() - start;
436→    logInfo("observer.llm.root_cause", "Root cause classification completed", {
437→      latencyMs,
438→      category: result.object.category,
439→      confidence: result.object.confidence,
440→      shouldPropose: result.object.should_propose_learning,
441→    });
442→
443→    return result.object;
444→  } catch (error) {
445→    const latencyMs = Date.now() - start;
446→    logError("observer.llm.root_cause_error", "Root cause classification failed", {
447→      error,
448→      latencyMs,
449→    });
450→    return undefined;
451→  }
452→}
453→
454→// ---------------------------------------------------------------------------
455→// Dual gate: decide whether to propose learning or create observation
456→// ---------------------------------------------------------------------------
457→
458→/**
459→ * Applies the dual gate: should_propose_learning AND confidence >= threshold.
460→ */
461→function shouldProposeLearning(classification: RootCauseClassification): boolean {
462→  return classification.should_propose_learning && classification.confidence >= CONFIDENCE_THRESHOLD;
463→}
464→
465→/**
466→ * Maps a root cause classification to a CreateLearningInput.
467→ */
468→function rootCauseToLearningInput(
469→  classification: RootCauseClassification,
470→  cluster: ObservationCluster,
471→): CreateLearningInput {
472→  return {
473→    text: classification.proposed_learning_text,
474→    learningType: classification.proposed_learning_type,
475→    source: "agent",
476→    suggestedBy: "observer",
477→    patternConfidence: classification.confidence,
478→    targetAgents: classification.target_agents,
479→    evidenceIds: cluster.observations.map((obs) => ({
480→      table: "observation" as const,
481→      id: obs.id,
482→    })),
483→  };
484→}
