486→// ---------------------------------------------------------------------------
487→// Query existing active learnings for classification context
488→// ---------------------------------------------------------------------------
489→
490→async function queryActiveLearningTexts(
491→  surreal: Surreal,
492→  workspaceRecord: RecordId<"workspace", string>,
493→): Promise<string[]> {
494→  const [rows] = await surreal.query<[Array<{ text: string; created_at: string }>]>(
495→    `SELECT text, created_at FROM learning
496→     WHERE workspace = $ws AND status = "active"
497→     ORDER BY created_at DESC
498→     LIMIT 20;`,
499→    { ws: workspaceRecord },
500→  );
501→  return (rows ?? []).map((r) => r.text);
