580→// ---------------------------------------------------------------------------
581→// Diagnostic pipeline orchestrator
582→// ---------------------------------------------------------------------------
583→
584→/**
585→ * Runs the observation clustering, coverage check, and root cause classification pipeline.
586→ *
587→ * Pipeline:
588→ * 1. Query recent observations with embeddings
589→ * 2. Cluster by pairwise similarity
590→ * 3. For each cluster, check coverage against active learnings
591→ * 4. For uncovered clusters, classify root cause via LLM
592→ * 5. Propose learning or create observation based on dual gate
593→ */
594→export async function runDiagnosticClustering(
595→  surreal: Surreal,
596→  workspaceRecord: RecordId<"workspace", string>,
597→  observerModel: LanguageModel,
598→  embeddingModel: EmbeddingModel,
599→  embeddingDimension: number,
600→): Promise<{
601→  clusters: ObservationCluster[];
602→  uncoveredClusters: ObservationCluster[];
603→  result: DiagnosticResult;
604→}> {
605→  const diagnosticResult: DiagnosticResult = {
606→    learning_proposals_created: 0,
607→    coverage_skips: 0,
608→    clusters_found: 0,
609→  };
610→
611→  // Step 1: Query recent observations
612→  const observations = await queryRecentObservationsWithEmbeddings(
613→    surreal,
614→    workspaceRecord,
615→  );
616→
617→  if (observations.length < MINIMUM_CLUSTER_SIZE) {
618→    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
619→  }
620→
621→  // Step 2: Cluster by similarity (pure)
622→  const clusters = clusterObservationsBySimilarity(observations);
623→  diagnosticResult.clusters_found = clusters.length;
624→
625→  if (clusters.length === 0) {
626→    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
627→  }
628→
629→  // Step 3: Coverage check for each cluster
630→  const uncoveredClusters: ObservationCluster[] = [];
631→
632→  for (const cluster of clusters) {
633→    // Compute cluster centroid embedding (average of all observation embeddings)
634→    // to reduce noise from individual observation text variations
635→    const clusterObsWithEmbeddings = cluster.observations
636→      .map((co) => observations.find((o) => o.id === co.id))
637→      .filter((o): o is ObservationWithEmbedding => o !== undefined && o.embedding.length > 0);
638→
639→    if (clusterObsWithEmbeddings.length === 0) {
640→      uncoveredClusters.push(cluster);
641→      continue;
642→    }
643→
644→    const centroidEmbedding = computeCentroidEmbedding(
645→      clusterObsWithEmbeddings.map((o) => o.embedding),
646→    );
647→
648→    const coverage = await checkCoverageAgainstActiveLearnings(
649→      surreal,
650→      workspaceRecord,
651→      centroidEmbedding,
652→    );
653→
654→    if (coverage.covered) {
655→      logInfo("observer.learning.coverage_skip", "Cluster pattern already covered by active learning", {
656→        clusterSize: cluster.clusterSize,
657→        matchedLearningText: coverage.matchedLearningText,
658→        similarity: coverage.similarity,
659→      });
660→      diagnosticResult.coverage_skips += 1;
661→      continue;
662→    }
663→
664→    // Check if a dismissed learning already covers this pattern
665→    const dismissedCheck = await checkDismissedLearningForCluster(
666→      surreal,
667→      workspaceRecord,
668→      centroidEmbedding,
669→    );
670→
671→    if (dismissedCheck.covered) {
672→      logInfo("observer.learning.dismissed_skip", "Cluster pattern matches a previously dismissed learning", {
673→        clusterSize: cluster.clusterSize,
674→        matchedLearningText: dismissedCheck.matchedLearningText,
675→        similarity: dismissedCheck.similarity,
676→      });
677→      diagnosticResult.coverage_skips += 1;
678→    } else {
679→      uncoveredClusters.push(cluster);
680→    }
681→  }
682→
683→  // Step 4: Root cause classification for uncovered clusters
684→  if (uncoveredClusters.length > 0) {
685→    const existingLearnings = await queryActiveLearningTexts(surreal, workspaceRecord);
686→
687→    for (const cluster of uncoveredClusters) {
688→      const { proposed } = await processUncoveredCluster(
689→        surreal,
690→        workspaceRecord,
691→        observerModel,
692→        cluster,
693→        existingLearnings,
694→        embeddingModel,
695→        embeddingDimension,
696→      );
697→
698→      if (proposed) {
699→        diagnosticResult.learning_proposals_created += 1;
700→      }
701→    }
702→  }
703→
704→  return { clusters, uncoveredClusters, result: diagnosticResult };
705→}
