 3→-- Learning table: behavioral rules injected into agent prompts at runtime
 4→DEFINE TABLE learning SCHEMAFULL;
 5→
 6→DEFINE FIELD text ON learning TYPE string;
 7→DEFINE FIELD learning_type ON learning TYPE string
 8→  ASSERT $value IN ["constraint", "instruction", "precedent"];
 9→DEFINE FIELD status ON learning TYPE string
10→  ASSERT $value IN ["active", "pending_approval", "dismissed", "superseded", "deactivated"];
11→DEFINE FIELD source ON learning TYPE string
12→  ASSERT $value IN ["human", "agent"];
13→DEFINE FIELD priority ON learning TYPE string
14→  DEFAULT "medium"
15→  ASSERT $value IN ["low", "medium", "high"];
16→DEFINE FIELD target_agents ON learning TYPE array<string>;
17→DEFINE FIELD workspace ON learning TYPE record<workspace>;
18→
19→-- Agent suggestion metadata
20→DEFINE FIELD suggested_by ON learning TYPE option<string>;
21→DEFINE FIELD pattern_confidence ON learning TYPE option<float>;
22→
23→-- Audit trail: creation
24→DEFINE FIELD created_by ON learning TYPE option<record<identity>>;
25→DEFINE FIELD created_at ON learning TYPE datetime;
26→DEFINE FIELD updated_at ON learning TYPE option<datetime>;
27→
28→-- Audit trail: approval
29→DEFINE FIELD approved_by ON learning TYPE option<record<identity>>;
30→DEFINE FIELD approved_at ON learning TYPE option<datetime>;
31→DEFINE FIELD activated_at ON learning TYPE option<datetime>;
32→
33→-- Audit trail: dismissal
34→DEFINE FIELD dismissed_by ON learning TYPE option<record<identity>>;
35→DEFINE FIELD dismissed_at ON learning TYPE option<datetime>;
36→DEFINE FIELD dismissed_reason ON learning TYPE option<string>;
37→
38→-- Audit trail: deactivation
39→DEFINE FIELD deactivated_by ON learning TYPE option<record<identity>>;
40→DEFINE FIELD deactivated_at ON learning TYPE option<datetime>;
