42→-- Embedding for semantic search
43→DEFINE FIELD embedding ON learning TYPE option<array<float>>;
44→
45→-- Indexes
46→DEFINE INDEX idx_learning_workspace_status ON learning FIELDS workspace, status;
47→DEFINE INDEX idx_learning_embedding ON learning FIELDS embedding HNSW DIMENSION 1536 DIST COSINE;
